Here is a complete, single-file HTML solution using **Three.js**. This code creates a 3D scene with a ground plane, lighting, and a simple house structure (walls and a roof) that you can rotate and zoom around.

### How to use this:
1.  Copy the code below.
2.  Save it as an `.html` file (e.g., `house.html`).
3.  Open that file in any modern web browser.

```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>3D House Render</title>
    <style>
        body { margin: 0; overflow: hidden; background-color: #87CEEB; }
        canvas { display: block; }
        #info {
            position: absolute;
            top: 10px;
            width: 100%;
            text-align: center;
            color: white;
            font-family: sans-serif;
            font-weight: bold;
            text-shadow: 1px 1px 2px black;
            pointer-events: none;
        }
    </style>
</head>
<body>
    <div id="info">Left Click: Rotate | Right Click: Pan | Scroll: Zoom</div>

    <!-- Import Three.js from a CDN -->
    <script type="importmap">
        {
            "imports": {
                "three": "https://unpkg.com/three@0.160.0/build/three.module.js",
                "three/addons/": "https://unpkg.com/three@0.160.0/examples/jsm/"
            }
        }
    </script>

    <script type="module">
        import * as THREE from 'three';
        import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

        // 1. Scene Setup
        const scene = new THREE.Scene();
        scene.background = new THREE.Color(0x87CEEB); // Sky blue
        scene.fog = new THREE.Fog(0x87CEEB, 20, 100);

        // 2. Camera Setup
        const camera = new THREE.PerspectiveCamera(60, window.innerWidth / window.innerHeight, 0.1, 1000);
        camera.position.set(5, 5, 8);

        // 3. Renderer Setup
        const renderer = new THREE.WebGLRenderer({ antialias: true });
        renderer.setSize(window.innerWidth, window.innerHeight);
        renderer.shadowMap.enabled = true; // Enable shadows
        document.body.appendChild(renderer.domElement);

        // 4. Controls (Orbit)
        const controls = new OrbitControls(camera, renderer.domElement);
        controls.enableDamping = true;

        // 5. Lighting
        const ambientLight = new THREE.AmbientLight(0xffffff, 0.6);
        scene.add(ambientLight);

        const dirLight = new THREE.DirectionalLight(0xffffff, 1);
        dirLight.position.set(10, 20, 10);
        dirLight.castShadow = true;
        dirLight.shadow.mapSize.width = 2048;
        dirLight.shadow.mapSize.height = 2048;
        scene.add(dirLight);

        // 6. Create the House
        const houseGroup = new THREE.Group();

        // Materials
        const wallMaterial = new THREE.MeshStandardMaterial({ color: 0xeeeeee }); // White walls
        const roofMaterial = new THREE.MeshStandardMaterial({ color: 0x8B4513 }); // Brown roof
        const floorMaterial = new THREE.MeshStandardMaterial({ color: 0x5c4033 }); // Dark wood floor

        // --- The Floor ---
        const floorGeo = new THREE.BoxGeometry(4, 0.2, 4);
        const floor = new THREE.Mesh(floorGeo, floorMaterial);
        floor.position.y = 0;
        floor.receiveShadow = true;
        houseGroup.add(floor);

        // --- The Walls ---
        const wallHeight = 2;
        const wallThickness = 0.2;
        const wallGeo = new THREE.BoxGeometry(4, wallHeight, 0.2);
        const wall = new THREE.Mesh(wallGeo, wallMaterial);
        wall.position.y = wallHeight / 2;
        wall.castShadow = true;
        wall.receiveShadow = true;
        houseGroup.add(wall);

        // --- The Roof (Pyramid) ---
        const roofHeight = 2;
        const roofGeo = new THREE.ConeGeometry(3.5, roofHeight, 4); // 4 segments for a pyramid
        const roof = new THREE.Mesh(roofGeo, roofMaterial);
        roof.position.y = wallHeight + roofHeight / 2;
        roof.castShadow = true;
        houseGroup.add(roof);

        // --- Door ---
        const doorGeo = new THREE.BoxGeometry(1, 2, 0.1);
        const doorMat = new THREE.MeshStandardMaterial({ color: 0x333333 });
        const door = new THREE.Mesh(doorGeo, doorMat);
        door.position.set(0, 1, 1.9); // Slightly inside the wall
        houseGroup.add(door);

        // --- Windows ---
        const windowGeo = new THREE.BoxGeometry(1, 1, 0.1);
        const windowMat = new THREE.MeshStandardMaterial({ color: 0x88ccff }); // Blue glass

        // Left Window
        const win1 = new THREE.Mesh(windowGeo, windowMat);
        win1.position.set(-1.2, 1.5, 1.9);
        houseGroup.add(win1);

        // Right Window
        const win2 = new THREE.Mesh(windowGeo, windowMat);
        win2.position.set(1.2, 1.5, 1.9);
        houseGroup.add(win2);

        scene.add(houseGroup);

        // 7. Ground Plane (Grass)
        const groundGeo = new THREE.PlaneGeometry(100, 100);
        const groundMat = new THREE.MeshStandardMaterial({ color: 0x4caf50 });
        const ground = new THREE.Mesh(groundGeo, groundMat);
        ground.rotation.x = -Math.PI / 2;
        ground.position.y = -0.1;
        ground.receiveShadow = true;
        scene.add(ground);

        // 8. Animation Loop
        function animate() {
            requestAnimationFrame(animate);
            controls.update();
            renderer.render(scene, camera);
        }

        // Handle window resize
        window.addEventListener('resize', () => {
            camera.aspect = window.innerWidth / window.innerHeight;
            camera.updateProjectionMatrix();
            renderer.setSize(window.innerWidth, window.innerHeight);
        });

        animate();
    </script>
</body>
</html>
```

### What this code does:
1.  **Imports Three.js:** It pulls the library directly from a CDN, so you don't need to install anything.
2.  **Sets up the Scene:** Creates a sky-blue background and adds fog for depth.
3.  **Builds the House:**
    *   **Floor:** A simple box.
    *   **Walls:** A central box.
    *   **Roof:** A cone geometry (4-sided) to create a pyramid shape.
    *   **Details:** Adds a door and two windows using smaller boxes.
4.  **Lighting:** Adds a directional light (sun) that casts shadows, making the house look 3D.
5.  **Interactivity:** Uses `OrbitControls` so you can click and drag to rotate the view, right-click to pan, and scroll to zoom.

### How to customize it:
*   **Change Colors:** Look for `0xeeeeee` (walls) or `0x8B4513` (roof) and replace them with any hex color code (e.g., `0xff0000` for red).
*   **Change Size:** Modify the numbers in `BoxGeometry(width, height, depth)`.
*   **Add Textures:** You can replace the `MeshStandardMaterial` with `MeshStandardMaterial({ map: textureLoader.load('url.jpg') })` to use real images for walls or floors.
